// Helper function to parse array string "[1, 2, 3]" into std::vector<int>
std::vector<int> parseVector(const std::string& s) {
    std::vector<int> vec;
    std::string temp = s;
    // Remove brackets
    if (temp.length() >= 2 && temp.front() == '[' && temp.back() == ']') {
        temp = temp.substr(1, temp.length() - 2);
    }
    std::stringstream ss(temp);
    std::string segment;
    while(std::getline(ss, segment, ',')) {
        try {
            vec.push_back(std::stoi(segment));
        } catch (const std::invalid_argument& e) {
            // Handle error, e.g., non-integer in list
            std::cerr << "Invalid argument: " << segment << std::endl;
        } catch (const std::out_of_range& e) {
            // Handle error, e.g., number too large
            std::cerr << "Out of range: " << segment << std::endl;
        }
    }
    return vec;
}

// Helper function to convert vector to string for output
std::string vecToString(const std::vector<int>& vec) {
    std::ostringstream oss;
    oss << "[";
    for (size_t i = 0; i < vec.size(); ++i) {
        oss << vec[i];
        if (i < vec.size() - 1) {
            oss << ", ";
        }
    }
    oss << "]";
    return oss.str();
}

